from dataclasses import dataclass
from typing import Callable

@dataclass
class EvalResult:
    prompt_version: str
    example_id: str
    output: str
    score: float         # 0.0–1.0
    latency_ms: float
    input_tokens: int
    output_tokens: int

class LLMEvalSuite:
    """Lightweight eval harness: fast deterministic checks + sampled judge evals."""

    def __init__(self, model_fn: Callable[[str, str], str]):
        self.model_fn = model_fn  # (system_prompt, user_message) -> response

    def exact_match(self, system: str, user: str, expected: str) -> float:
        out = self.model_fn(system, user)
        return 1.0 if expected.strip().lower() in out.lower() else 0.0

    def regex_check(self, system: str, user: str, pattern: str) -> float:
        import re
        out = self.model_fn(system, user)
        return 1.0 if re.search(pattern, out) else 0.0

    def llm_judge(self, system: str, user: str, rubric: str,
                  judge_model: str = "claude-haiku-4-5-20251001") -> float:
        import anthropic, json
        out = self.model_fn(system, user)
        judge_prompt = f"""Rate the following response on this rubric:

RUBRIC: {rubric}
RESPONSE: {out}

Return JSON: {{"score": <0.0 to 1.0>, "reason": "<one sentence>"}}"""
        client = anthropic.Anthropic()
        r = client.messages.create(
            model=judge_model, max_tokens=256,
            messages=[{"role": "user", "content": judge_prompt}]
        )
        return json.loads(r.content[0].text)["score"]

    def run_suite(self, cases: list[dict]) -> dict:
        results = []
        for case in cases:
            method = getattr(self, case["type"])
            score = method(**{k: v for k, v in case.items() if k != "type"})
            results.append(score)
        n = len(results)
        return {"pass_rate": sum(1 for s in results if s >= 0.7) / n,
                "mean_score": sum(results) / n,
                "n": n}

import anthropic, time

client = anthropic.Anthropic()

def measure_streaming_latency(prompt: str, model: str) -> dict:
    start = time.perf_counter()
    first_token_time = None
    token_count = 0

    with client.messages.stream(
        model=model,
        max_tokens=512,
        messages=[{"role": "user", "content": prompt}]
    ) as stream:
        for text in stream.text_stream:
            if first_token_time is None:
                first_token_time = time.perf_counter()
            token_count += len(text.split())   # approximate

    end = time.perf_counter()
    ttft = (first_token_time - start) * 1000 if first_token_time else None
    e2e  = (end - start) * 1000
    tps  = token_count / ((end - (first_token_time or start))) if first_token_time else 0

    return {"ttft_ms": round(ttft, 1),
            "e2e_ms":  round(e2e, 1),
            "tps":     round(tps, 1),
            "tokens":  token_count}

result = measure_streaming_latency(
    "Explain the EU AI Act risk tiers in 200 words.",
    "claude-haiku-4-5-20251001"   # fastest model for latency-sensitive paths
)
print(result)
